import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Location } from '../../core/models';

/**
 * Locations list (manager only). Physical stock locations that StockLevels and
 * movements reference. Managers can create and edit locations.
 */
@Component({
  selector: 'app-locations-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './locations-list.component.html',
  styleUrl: './locations-list.component.css',
})
export class LocationsListComponent {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);
}
